using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Set up chat client with tools ---
var notepad = new Notepad();
var tools = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ],
    ToolMode = ChatToolMode.Auto
};

IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Agent loop ---
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to research the given topic thoroughly.
        You have access to the following tools:
        - SearchAsync: Search the web for information. Use varied queries to get broad coverage.
        - AddNote: Save important findings as notes for later summarization.
        - GetNotes: Retrieve all notes you have taken so far.

        Strategy:
        1. Perform 2-3 different web searches to gather diverse information on the topic.
        2. After each search, take notes on the key findings.
        3. Once you have gathered enough information, retrieve your notes and provide a
           comprehensive summary of your research.

        Always end with a final summary section that synthesizes all findings.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}")
};

var response = await client.GetResponseAsync(messages, tools);
Console.WriteLine("\n--- Research Summary ---\n");
Console.WriteLine(response.Text);

// --- Tool Implementations ---

/// <summary>Web search tool that queries a search engine and returns results.</summary>
static class WebSearchTool
{
    [Description("Search the web for information on a query. Returns a list of relevant snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        try
        {
            using var http = new HttpClient();
            http.DefaultRequestHeaders.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await http.GetStringAsync(url);

            // Extract text snippets from result blocks
            var snippets = ExtractSnippets(html);
            if (snippets.Count == 0)
                return "No results found for this query.";

            return string.Join("\n\n", snippets.Take(5).Select((s, i) => $"[{i + 1}] {s}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ExtractSnippets(string html)
    {
        var snippets = new List<string>();
        var marker = "class=\"result__snippet\"";
        var idx = 0;
        while ((idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) != -1)
        {
            var start = html.IndexOf('>', idx) + 1;
            var end = html.IndexOf('<', start);
            if (start > 0 && end > start)
            {
                var text = WebUtility.HtmlDecode(html[start..end]).Trim();
                if (!string.IsNullOrWhiteSpace(text))
                    snippets.Add(text);
            }
            idx = end > 0 ? end : idx + 1;
        }
        return snippets;
    }
}

/// <summary>Note-taking tool that stores research findings.</summary>
class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key findings from searches.")]
    public string AddNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all research notes taken so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", _notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }
}

